.darma-loader-uiverse-waveform-pill {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-waveform-pill__wave-menu {
  border: 4px solid #545FE5;
  border-radius: 50px;
  width: 200px;
  height: 45px;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 0;
  margin: 0;
  cursor: pointer;
  transition: ease 0.2s;
  position: relative;
  background: #fff;
}

.darma-loader-uiverse-waveform-pill__wave-menu li {
list-style: none;
height: 30px;
width: 4px;
border-radius: 10px;
background: #545FE5;
margin: 0 6px;
padding: 0;
animation-name: darma-loader-uiverse-waveform-pill-wave1;
animation-duration: 0.3s;
animation-iteration-count: infinite;
animation-direction: alternate;
transition: ease 0.2s;
}

.darma-loader-uiverse-waveform-pill__wave-menu:hover > li {
background: #fff;
}

.darma-loader-uiverse-waveform-pill__wave-menu:hover {
background: #545FE5;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(2) {
animation-name: darma-loader-uiverse-waveform-pill-wave2;
animation-delay: 0.2s;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(3) {
animation-name: darma-loader-uiverse-waveform-pill-wave3;
animation-delay: 0.23s;
animation-duration: 0.4s;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(4) {
animation-name: darma-loader-uiverse-waveform-pill-wave4;
animation-delay: 0.1s;
animation-duration: 0.3s;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(5) {
animation-delay: 0.5s;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(6) {
animation-name: darma-loader-uiverse-waveform-pill-wave2;
animation-duration: 0.5s;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(8) {
animation-name: darma-loader-uiverse-waveform-pill-wave4;
animation-delay: 0.4s;
animation-duration: 0.25s;
}

.darma-loader-uiverse-waveform-pill__wave-menu li:nth-child(9) {
animation-name: darma-loader-uiverse-waveform-pill-wave3;
animation-delay: 0.15s;
}

@keyframes darma-loader-uiverse-waveform-pill-wave1 {
from {
transform: scaleY(1);
}

to {
transform: scaleY(0.5);
}
}

@keyframes darma-loader-uiverse-waveform-pill-wave2 {
from {
transform: scaleY(0.3);
}

to {
transform: scaleY(0.6);
}
}

@keyframes darma-loader-uiverse-waveform-pill-wave3 {
from {
transform: scaleY(0.6);
}

to {
transform: scaleY(0.8);
}
}

@keyframes darma-loader-uiverse-waveform-pill-wave4 {
from {
transform: scaleY(0.2);
}

to {
transform: scaleY(0.5);
}
}

